
-- Primeiro as tabelas de LOG (que não têm dependências)
DROP TABLE IF EXISTS log_emprestimo CASCADE;
DROP TABLE IF EXISTS log_transacao CASCADE;
DROP TABLE IF EXISTS log_cliente CASCADE;
DROP TABLE IF EXISTS log_cartao CASCADE;
DROP TABLE IF EXISTS log_conta CASCADE;

-- Depois as tabelas com chaves estrangeiras (Filhas)
DROP TABLE IF EXISTS Emprestimo CASCADE;
DROP TABLE IF EXISTS Transacao CASCADE; 
DROP TABLE IF EXISTS Cartao CASCADE;
DROP TABLE IF EXISTS Conta CASCADE;

-- Por fim, as tabelas base (Mães)
DROP TABLE IF EXISTS Cliente CASCADE;
DROP TABLE IF EXISTS Endereco CASCADE;

CREATE TABLE Endereco (
    id_endereco SERIAL PRIMARY KEY,
    cep VARCHAR(9) NOT NULL,
    rua VARCHAR(150) NOT NULL,
    numero VARCHAR(10) NOT NULL,
    complemento VARCHAR(100),
    bairro VARCHAR(100) NOT NULL,
    cidade VARCHAR(100) NOT NULL,
    estado CHAR(2) NOT NULL
);

CREATE TABLE Cliente (
    id_cliente SERIAL PRIMARY KEY,
    nome_cliente VARCHAR(150) NOT NULL,
    cpf CHAR(11) NOT NULL UNIQUE,
    telefone VARCHAR(15),
    email VARCHAR(150) UNIQUE,
    score  NUMERIC(15,2) DEFAULT 0.00,
    id_endereco INT,

    CONSTRAINT fk_cliente_endereco
        FOREIGN KEY (id_endereco)
        REFERENCES Endereco(id_endereco)
);

CREATE TABLE Conta (
    id_conta SERIAL PRIMARY KEY,
    numero_conta VARCHAR(20) NOT NULL UNIQUE,
    tipo_conta VARCHAR(30) NOT NULL,
    saldo NUMERIC(15,2) DEFAULT 0.00,
    data_abertura TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    status VARCHAR(20) DEFAULT 'ATIVA',
    senha VARCHAR(15),
    id_cliente INT NOT NULL,

    CONSTRAINT fk_conta_cliente
        FOREIGN KEY (id_cliente)
        REFERENCES Cliente(id_cliente)
        ON DELETE CASCADE
);

CREATE TABLE Cartao (
    id_cartao SERIAL PRIMARY KEY,
    numero_cartao VARCHAR(16) NOT NULL UNIQUE,
    validade DATE NOT NULL,
    cvv CHAR(3) NOT NULL,
    tipo_cartao VARCHAR(20) NOT NULL,
    status VARCHAR(20) DEFAULT 'ATIVO',
    id_conta INT NOT NULL,
    senha VARCHAR(15),
    limite_cartao NUMERIC(15,2) DEFAULT 0.00,

    CONSTRAINT fk_cartao_conta
        FOREIGN KEY (id_conta)
        REFERENCES Conta(id_conta)
        ON DELETE CASCADE
);

CREATE TABLE Transacao (
    id_transacao SERIAL PRIMARY KEY,
    valor NUMERIC(15,2) NOT NULL,
    tipo_transacao VARCHAR(50) NOT NULL,
    descricao TEXT,
    data_transacao TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    id_conta INT NOT NULL,
    id_cartao INT,
    status VARCHAR(20) DEFAULT 'INVALIDO',

    CONSTRAINT fk_transacao_conta
        FOREIGN KEY (id_conta)
        REFERENCES Conta(id_conta),

    CONSTRAINT fk_transacao_cartao
        FOREIGN KEY (id_cartao)
        REFERENCES Cartao(id_cartao)
);

CREATE TABLE Emprestimo (
    id_emprestimo SERIAL PRIMARY KEY,
    valor_total NUMERIC(15,2) NOT NULL,
    taxa_juros NUMERIC(5,2) NOT NULL,
    quantidade_parcelas INT NOT NULL,
    data_contratacao DATE DEFAULT CURRENT_DATE,
    status VARCHAR(20) DEFAULT 'PENDENTE',
    id_conta INT NOT NULL,

    CONSTRAINT fk_emprestimo_conta
        FOREIGN KEY (id_conta)
        REFERENCES Conta(id_conta)
);

-- TABELAS DE LOG

CREATE TABLE log_emprestimo (
    id_log SERIAL PRIMARY KEY,
    id_emprestimo INT NOT NULL,
    id_conta INT NOT NULL,
    valor_total NUMERIC(15,2),
    taxa_juros NUMERIC(5,2),
    quantidade_parcelas INT,
    data_contratacao DATE,
    status VARCHAR(20),
    data_log TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE log_transacao (
    id_log SERIAL PRIMARY KEY,
    id_transacao INT NOT NULL,
    valor NUMERIC(15,2),
    id_conta INT,
    data_transacao TIMESTAMP,
    data_log TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    tipo_transacao VARCHAR(50) NOT NULL,
    status VARCHAR(20) DEFAULT 'INVALIDO'
);

CREATE TABLE log_cliente (
    id_log SERIAL PRIMARY KEY,
    id_cliente INT NOT NULL,
    cpf CHAR(11),
    id_endereco INT,
    score  NUMERIC(15,2) DEFAULT 0.00,
    data_log TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE log_cartao (
    id_log SERIAL PRIMARY KEY,
    id_cartao INT NOT NULL,
    numero_cartao VARCHAR(16),
    validade DATE,
    cvv CHAR(3),
    tipo_cartao VARCHAR(20),
    id_conta INT,
    data_log TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE log_conta (
    id_log SERIAL PRIMARY KEY,
    id_conta INT NOT NULL,
    numero_conta VARCHAR(20),
    tipo_conta VARCHAR(30),
    saldo NUMERIC(15,2),
    data_abertura TIMESTAMP,
    id_cliente INT,
    status VARCHAR(20),
    data_log TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

--criação de log transacao
create or replace function fn_log_transacao()

returns trigger language plpgsql as $$

begin


	values (new.id_transacao, new.valor, new.id_conta, new.status, new.data_transacao, new.tipo_transacao, now());
	
	return new;
end; $$;

create trigger trg_log_transacao

after insert on transacao

for each row execute function fn_log_transacao();

--criação de log pra emprestimoa

create or replace function fn_log_emprestimo()

returns trigger language plpgsql as $$

begin


	values (new.id_emprestimo, new.valor_total, new.taxa_juros, new.quantidade_parcelas, new.data_contratacao, new.status, new.id_conta, now());
	
	return new;
end; $$;
 
create trigger trg_log_emprestimo

after insert on emprestimo

for each row execute function fn_log_emprestimo();

--criação de log pra cliente
CREATE OR REPLACE FUNCTION fn_log_cliente()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
    VALUES (NEW.id_cliente, NEW.cpf, NEW.id_endereco, new.score ,now());
    
    RETURN NEW;
END; $$;
CREATE TRIGGER trg_log_cliente
AFTER INSERT ON cliente
FOR EACH ROW EXECUTE FUNCTION fn_log_cliente();

--criação de log para conta
create or replace function fn_log_conta()
returns trigger language plpgsql as $$
begin
    values (new.id_conta, new.numero_conta, new.tipo_conta, new.saldo, new.data_abertura, new.status,new.id_cliente, now());
    
    return new;
end; $$;
create trigger trg_log_conta
after insert on conta
for each row execute function fn_log_conta();

--criação de log para cartão
create or replace function fn_log_cartao()
returns trigger language plpgsql as $$
begin
    values (new.id_cartao, new.numero_cartao, new.validade, new.cvv, new.tipo_cartao, new.id_conta, now());
    
    return new;
end; $$;
create trigger trg_log_cartao
after insert on cartao
for each row execute function fn_log_cartao();

--verificação se é maior que 0
create or replace function fn_validar_pagamento()
returns trigger language plpgsql as $$
begin
	if new.valor<=0 then
		raise exception
		 'Valor inválido:R$ %. Deve ser maior que 0!', new.valor;
	end if;
	return new;
end; $$;
create trigger trg_validar_pagamento
before insert on transacao
for each row execute function fn_validar_pagamento();

--verificação se existe dinheiro na conta e coloca valido ou invalido

create or replace function fn_validar_transacao_saldo()
returns trigger language plpgsql as $$
declare
    v_saldo_atual decimal;
begin
    -- Busca o saldo atual da conta
    select saldo into v_saldo_atual from conta where id_conta = new.id_conta;

    -- Se o valor for maior que o saldo, marca como invalido
    if new.valor > v_saldo_atual then
        new.status := 'INVALIDO';
    else
        new.status := 'VALIDO';
    end if;

    return new;
end; $$;

create trigger trg_validar_transacao_saldo
before insert on transacao
for each row execute function fn_validar_transacao_saldo();

--proteje os dados
create or replace function fn_atualizar_saldo_conta()
returns trigger language plpgsql as $$
begin
    -- Só mexe no saldo se a transação foi marcada como válida pela trigger anterior
    if new.status = 'valido' then
        update conta 
        set saldo = saldo - new.valor 
        where id_conta = new.id_conta;
    end if;

    return new;
end; $$;

create trigger trg_atualizar_saldo_pos_transacao
after insert on transacao
for each row execute function fn_atualizar_saldo_conta();

--trigger de bloquear o cartão
create or replace function fn_verificar_limite()
returns trigger language plpgsql as $$
DECLARE
    total_gasto_24h DECIMAL(10,2);
	fn_limite_cartao   DECIMAL(10,2);
begin
    SELECT limite_cartao INTO fn_limite_cartao FROM cartao WHERE id_cartao = NEW.id_cartao;
	SELECT SUM(valor) INTO total_gasto_24h 
    FROM transacao
    WHERE id_cartao = NEW.id_cartao 
    AND data_transacao >= NOW() - INTERVAL '24 hours';
	IF total_gasto_24h >= (fn_limite_cartao * 0.90) THEN
        -- 3. Bloqueia o cartão preventivamente
        UPDATE cartao 
        SET status = 'bloqueado_preventivo' 
        WHERE id_cartao = NEW.id_cartao;
        
        RAISE NOTICE 'Cartão % bloqueado: Gasto de 90%% do limite atingido em 24h.', NEW.id_cartao;
    END IF;

    return new;
end; $$;

create trigger trg_verificar_limite
after insert on transacao
for each row execute function fn_verificar_limite();

CREATE OR REPLACE FUNCTION calcular_score_cliente(p_id_cliente INT)
RETURNS INT
LANGUAGE plpgsql
AS $$
DECLARE
    v_score INT := 0;
BEGIN

    -- Contas ativas
    v_score := v_score + (SELECT COUNT(*) * 20 FROM Conta WHERE id_cliente = p_id_cliente AND status = 'ATIVA');

    -- Contas inativas
    v_score := v_score - (SELECT COUNT(*) * 10 FROM Conta WHERE id_cliente = p_id_cliente AND status != 'ATIVA');

    -- Saldo total
    v_score := v_score + (
        SELECT CASE
            WHEN COALESCE(SUM(saldo), 0) >= 10000 THEN 100
            WHEN COALESCE(SUM(saldo), 0) >= 3000  THEN 60
            WHEN COALESCE(SUM(saldo), 0) >= 500   THEN 30
            WHEN COALESCE(SUM(saldo), 0) < 0      THEN -80
            ELSE 0
        END
        FROM Conta WHERE id_cliente = p_id_cliente
    );

    -- Transações nos últimos 90 dias
    v_score := v_score + (
        SELECT CASE
            WHEN COUNT(*) >= 30 THEN 60
            WHEN COUNT(*) >= 10 THEN 35
            WHEN COUNT(*) >= 1  THEN 10
            ELSE -20
        END
        FROM Transacao t
        JOIN Conta c ON t.id_conta = c.id_conta
        WHERE c.id_cliente = p_id_cliente
          AND t.data_transacao >= NOW() - INTERVAL '90 days'
    );

    -- Empréstimos
    v_score := v_score + (SELECT COUNT(*) *  50 FROM Emprestimo e JOIN Conta c ON e.id_conta = c.id_conta WHERE c.id_cliente = p_id_cliente AND e.status = 'QUITADO');
    v_score := v_score - (SELECT COUNT(*) *  20 FROM Emprestimo e JOIN Conta c ON e.id_conta = c.id_conta WHERE c.id_cliente = p_id_cliente AND e.status = 'ATIVO');
    v_score := v_score - (SELECT COUNT(*) * 150 FROM Emprestimo e JOIN Conta c ON e.id_conta = c.id_conta WHERE c.id_cliente = p_id_cliente AND e.status = 'INADIMPLENTE');

    -- Cartões
    v_score := v_score + (SELECT COUNT(*) * 15 FROM Cartao ca JOIN Conta c ON ca.id_conta = c.id_conta WHERE c.id_cliente = p_id_cliente AND ca.status = 'ATIVO');
    v_score := v_score - (SELECT COUNT(*) * 25 FROM Cartao ca JOIN Conta c ON ca.id_conta = c.id_conta WHERE c.id_cliente = p_id_cliente AND ca.status = 'BLOQUEADO');

    RETURN GREATEST(0, LEAST(1000, v_score));

END;
$$;

CREATE OR REPLACE PROCEDURE calcular_score(p_id_cliente INT)
LANGUAGE plpgsql
AS $$
DECLARE
    v_score             NUMERIC(15,2) := 0.00;
    v_saldo_total       NUMERIC(15,2);
    v_qtd_emp_ativos    INT;
    v_qtd_emp_quitados  INT;
    v_qtd_transacoes    INT;
    v_cliente_existe    INT;
BEGIN

    SELECT COUNT(*) INTO v_cliente_existe
    FROM Cliente WHERE id_cliente = p_id_cliente;

    IF v_cliente_existe = 0 THEN
        RAISE EXCEPTION 'Cliente com id % não encontrado.', p_id_cliente;
    END IF;

    -- Saldo total
    SELECT COALESCE(SUM(saldo), 0) INTO v_saldo_total
    FROM Conta WHERE id_cliente = p_id_cliente;

    -- Empréstimos ativos e quitados
    SELECT
        COUNT(*) FILTER (WHERE e.status = 'PENDENTE'),
        COUNT(*) FILTER (WHERE e.status = 'QUITADO')
    INTO v_qtd_emp_ativos, v_qtd_emp_quitados
    FROM Emprestimo e
    JOIN Conta c ON c.id_conta = e.id_conta
    WHERE c.id_cliente = p_id_cliente;

    -- Quantidade de transações
    SELECT COUNT(*) INTO v_qtd_transacoes
    FROM Transacao t
    JOIN Conta c ON c.id_conta = t.id_conta
    WHERE c.id_cliente = p_id_cliente;

    -- ── SALDO ────────────────────────────────────
    IF v_saldo_total >= 10000 THEN
        v_score := v_score + 300;
    ELSIF v_saldo_total >= 1000 THEN
        v_score := v_score + 150;
    ELSIF v_saldo_total >= 100 THEN
        v_score := v_score + 50;
    END IF;

    -- ── EMPRÉSTIMOS QUITADOS ─────────────────────
    IF v_qtd_emp_quitados >= 2 THEN
        v_score := v_score + 300;
    ELSIF v_qtd_emp_quitados = 1 THEN
        v_score := v_score + 150;
    END IF;

    -- ── EMPRÉSTIMOS ATIVOS (penaliza) ────────────
    IF v_qtd_emp_ativos >= 3 THEN
        v_score := v_score - 200;
    ELSIF v_qtd_emp_ativos = 2 THEN
        v_score := v_score - 100;
    ELSIF v_qtd_emp_ativos = 1 THEN
        v_score := v_score - 30;
    END IF;

    -- ── TRANSAÇÕES ───────────────────────────────
    IF v_qtd_transacoes >= 20 THEN
        v_score := v_score + 200;
    ELSIF v_qtd_transacoes >= 5 THEN
        v_score := v_score + 100;
    ELSIF v_qtd_transacoes >= 1 THEN
        v_score := v_score + 50;
    END IF;

    -- Limita entre 0 e 1000
    v_score := GREATEST(0, LEAST(1000, v_score));

    UPDATE Cliente SET score = v_score WHERE id_cliente = p_id_cliente;

    SELECT id_cliente, cpf, id_endereco, v_score
    FROM Cliente WHERE id_cliente = p_id_cliente;

    RAISE NOTICE 'Score do cliente % atualizado para: %', p_id_cliente, v_score;

END;
$$;

